const body = $input.first().json.body || $input.first().json;
const uuidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;

if (!body.tenantId || !uuidRegex.test(body.tenantId)) {
  throw new Error('Invalid or missing tenantId');
}
if (!Array.isArray(body.sirets) || body.sirets.length === 0) {
  throw new Error('sirets must be a non-empty array');
}

// Validate each SIRET
body.sirets.forEach(siret => {
  if (!/^\d{14}$/.test(siret)) {
    throw new Error(`Invalid SIRET format: ${siret}`);
  }
});

return [{ json: {
  tenantId: body.tenantId,
  sirets: body.sirets
} }];

// Validate each SIRET with Luhn algorithm
const sirets = $node["02. Parser"].json.sirets;
const results = [];

sirets.forEach(siret => {
  let sum = 0;
  let doubled = false;
  for (let i = siret.length - 1; i >= 0; i--) {
    let digit = parseInt(siret[i], 10);
    if (doubled) {
      digit *= 2;
      if (digit > 9) digit -= 9;
    }
    sum += digit;
    doubled = !doubled;
  }

  const isValid = (sum % 10) === 0;
  results.push({
    siret: siret,
    luhn_valid: isValid,
    siren: siret.substring(0, 9)
  });
});

return { validations: results };

// Simulate batch API calls
const validations = $node["05. Validate All"].json.validations;
const results = [];

validations.forEach(v => {
  const apiResponse = {
    siret: v.siret,
    siren: v.siren,
    nic: v.siret.substring(9),
    denomination: `Entreprise ${v.siret}`,
    adresse: '123 Rue de la Paix',
    code_postal: '75000',
    ville: 'Paris',
    code_naf: '6202A',
    tranche_effectif: '10-19',
    date_creation_etablissement: '2020-01-15',
    etat_administratif: 'A',
    timestamp_verification: new Date().toISOString()
  };
  results.push(apiResponse);
});

return { api_responses: results };

return {
  success: true,
  message: 'SIRET batch verification completed',
  count: $node["02. Parser"].json.sirets.length,
  data: $node["06. Query API Batch"].json.api_responses
};
